/** A named gate condition that must evaluate to true before a route stage may execute. Gates enforce consent, capacity, schedule, policy, role, and notification-budget constraints. */
export interface AdmissionGate extends ZoelaBase {
  /** Machine-readable identifier for an AdmissionGate, used in runtime gate evaluation (e.g. 'consent', 'capacity', 'schedule'). */
  gate_code?: string;
}

/** Active membership of a person in a Connect Group. Terminal artifact of the ConnectGroupJoinRoute. Carries start date, status, and links back to the route receipt. */
export interface GroupMembership extends ZoelaBase {
  /** Links a GroupMembership record to the ConnectGroup the person is a member of. */
  membership_for_group?: string;
  /** The PersonProfile who holds this group membership. */
  membership_by_person?: string;
  /** Calendar date on which active membership began. Set when stage 8 (Membership Active) completes. */
  membership_start_date?: string;
  /** Lifecycle status of the membership record. Allowed values: active, inactive, waitlisted. */
  membership_status?: string;
  /** ISO-8601 datetime recording when the person joined the Connect Group. */
  joined_at?: string;
  /** The role held by the member within this Connect Group (e.g. leader, co-leader, member, apprentice). */
  member_role?: string;
  /** True when the membership is current and the person actively participates in the group. */
  member_is_active?: boolean;
}

/** An attendance record for a person at a Connect Group meeting. Required as evidence for stage 6 (First Meeting Attended). First-meeting flag drives follow-up trigger. */
export interface GroupAttendance extends ZoelaBase {
  /** Links an attendance record to the ConnectGroup meeting at which attendance is recorded. */
  attendance_for_group?: string;
  /** The PersonProfile whose attendance is being recorded. */
  attendance_by_person?: string;
  /** Calendar date of the Connect Group meeting for which attendance is recorded. */
  attendance_meeting_date?: string;
  /** True when this is the person's first attendance at any meeting of this Connect Group. Triggers stage 6 → stage 7 follow-up transition. */
  attendance_is_first?: boolean;
  /** Status of this attendance record. Allowed values: attended, absent, excused. */
  attendance_status?: string;
}

/** An invite issued to a person to join a specific Connect Group after an autonomic or manual match. Gated by CommunicationConsent and notification budget. */
export interface GroupInvite extends ZoelaBase {
  /** The ConnectGroup to which the person is being invited. */
  invite_for_group?: string;
  /** The PersonProfile receiving this invite. */
  invite_to_person?: string;
  /** ISO-8601 timestamp when the invite was dispatched. Maps to stage 4 OCEL event timestamp. */
  invite_sent_at?: string;
  /** ISO-8601 timestamp after which an unaccepted invite is automatically expired and the person may be re-matched. */
  invite_expires_at?: string;
  /** Lifecycle status of the GroupInvite. Allowed values: sent, accepted, declined, expired. */
  invite_status?: string;
  /** ISO-8601 timestamp when the person accepted the invite. Null if not yet accepted. */
  invite_accepted_at?: string;
  /** ISO-8601 timestamp when the person declined the invite. Null if not declined. */
  invite_declined_at?: string;
}

/** An expression of interest by a person seeking to join a Connect Group. Captures schedule/location preferences and drives the autonomic matching pipeline. */
export interface GroupInterest extends ZoelaBase {
  /** Links a GroupInterest to the specific ConnectGroup the person is interested in, if known. May be null when the system performs open matching. */
  interest_for_group?: string;
  /** Links a GroupInterest to the PersonProfile who submitted it. */
  interest_from_person?: string;
  /** Free-text or structured schedule preference (e.g. 'Tuesday evenings', 'Sunday mornings') captured at interest submission. */
  interest_schedule_preference?: string;
  /** Preferred geographic area or campus for Connect Group placement (e.g. 'Hollywood campus', 'Silver Lake'). */
  interest_location_preference?: string;
  /** Optional free-text notes from the person expressing interest, e.g. life stage, ministry interests, or accessibility requirements. */
  interest_notes?: string;
  /** ISO-8601 timestamp when the GroupInterest was submitted. Used as the OCEL event timestamp for stage 1. */
  interest_submitted_at?: string;
  /** Lifecycle status of the GroupInterest. Allowed values: pending, matched, waitlisted, refused. */
  interest_status?: string;
}

/** A Connect Group specifically designed for teenagers aged 12-17. Requires guardian consent for participation and applies additional safeguarding policies. */
export interface YouthConnectGroup extends ZoelaBase {
  /** True (default) when participation by a minor in this youth group requires explicit guardian consent on file. */
  requires_guardian_consent?: boolean;
}

/** The membership relationship linking a person to a Connect Group, recording their role, join date, and active status. */
export interface ConnectGroup extends ZoelaBase {
  /** Short alphanumeric code uniquely identifying the Connect Group within its campus (e.g. HLP-CG-01). Used as a routing key in the manufacturing pipeline. */
  group_code?: string;
  /** Recurrence cadence for group meetings. Allowed values: weekly, biweekly, monthly. */
  group_frequency?: string;
  /** Maximum number of members the group can accommodate. Used to determine open/closed status. */
  max_capacity?: number;
  /** Current number of active members in the group. Compared against maxCapacity to compute availability. */
  current_size?: number;
  /** Identifier of the person holding the primary leadership role for this Connect Group. */
  group_leader_id?: string;
  /** True when the group is accepting new members (currentSize < maxCapacity and group is active). */
  is_open?: boolean;
  /** Associates the Connect Group with the ZOE LA campus at which it primarily meets. */
  group_has_campus?: string;
  /** The generation segment this Connect Group is designed to serve. Drawn from the GenerationSegmentScheme vocabulary. */
  group_target_generation?: string;
}

/** A small-group community formation unit within ZOE LA. Functions as both a recurring gathering event and a formal organisational unit with defined membership and leadership. */
