  ocel_event_type?: string;
  /** Service Level Agreement (SLA) deadline for this stage in decimal hours. A route instance that has not advanced past this stage within the timeout is flagged for escalation. Null value indicates no deadline constraint. */
  timeout_hours?: number;
  /** Links a RouteStage to the ServiceRoute it belongs to. Every stage must belong to exactly one route. */
