  /** SKOS concept identifying the organizational role (e.g. VolunteerRole, PastorRole, MemberRole) that must be held by the agent executing this stage. Gate blocks execution if the executing user does not hold this role. */
  required_role?: string;
  /** SKOS concept identifying the consent classification that the subject must have granted before this stage can execute. Used for GDPR/CCPA and ministry data policy compliance gates. */
